import{_ as o,o as a,c as s,a2 as d}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"플랫폼 이관 US4~US7 + 마감 — 감사·결재·권한신청·메일/파일, 그리고 헌법에 새긴 참조 출처","description":"","frontmatter":{"slug":"us4-us7-phase10-complete","title":"플랫폼 이관 US4~US7 + 마감 — 감사·결재·권한신청·메일/파일, 그리고 헌법에 새긴 참조 출처","authors":[],"tags":["spec-kit","sdd","spring-boot","mybatis","audit","approval","migration","platform"],"created":"2026-05-31 15:20 (KST)","date":"2026-05-31T06:20:00.000Z"},"headers":[],"relativePath":"journal/2026-05-31-us4-us7-phase10-complete.md","filePath":"journal/2026-05-31-us4-us7-phase10-complete.md","lastUpdated":1781092690000}'),t={name:"journal/2026-05-31-us4-us7-phase10-complete.md"};function c(r,e,i,n,l,p){return a(),s("div",null,[...e[0]||(e[0]=[d(`<p>플랫폼 관리 기능 이관(feature 004)을 <strong>완결</strong>했다. 한 세션에서 US4(감사 추적)· US5(다단계 결재)·US6(권한 신청)·US7(메일·파일)을 차례로 끝내고, Phase 10(데모·격리· 성능·문서)까지 마감했다. 전체 <code>gradle :app:test</code> <strong>25/25 통과</strong>. 구현 자체보다 <strong>타겟 스키마와 이전 소스가 어긋난 지점</strong>, 그리고 그걸 어떻게 적응했는지가 기록할 가치가 있다.</p><h2 id="헌법에-참조-출처-를-새겼다" tabindex="-1">헌법에 &quot;참조 출처&quot;를 새겼다 <a class="header-anchor" href="#헌법에-참조-출처-를-새겼다" aria-label="Permalink to &quot;헌법에 &quot;참조 출처&quot;를 새겼다&quot;">​</a></h2><p>US5 들어가기 전에 헌법(<code>/speckit.constitution</code>)을 한 번 고쳤다. 그리드 관련은 <code>C:/ax/vugrid</code>, 이전(레거시) 소스는 <code>C:/ax/lego</code> 를 <strong>단일 참조 기준</strong>으로 삼는다는 절을 추가하고 v1.0.0 → v1.1.0. 입력은 <code>d:/ax/vugird</code> 였는데 그 드라이브가 없어 되물었고, 실제로는 <code>C:/ax/vugrid</code>(VuGrid TS 그리드 라이브러리)·<code>C:/ax/lego</code>(Clear Platform, Java17/SB3.5.11) 였다. 이 한 줄이 이후 US5·US6·US7 의 &quot;무엇을 보고 적응할지&quot;를 명확히 했다.</p><h2 id="us5-—-레거시는-pending-타겟은-current-step" tabindex="-1">US5 — 레거시는 PENDING, 타겟은 CURRENT_STEP <a class="header-anchor" href="#us5-—-레거시는-pending-타겟은-current-step" aria-label="Permalink to &quot;US5 — 레거시는 PENDING, 타겟은 CURRENT_STEP&quot;">​</a></h2><p>이전 소스의 결재는 <code>PENDING</code> 한 상태에서 &quot;모든 단계가 승인되면 완료&quot;였다. 타겟 data-model 은 다르다 — <code>DRAFT → IN_PROGRESS → APPROVED/REJECTED</code> 에 <strong><code>CURRENT_STEP</code> 순차 진행</strong>. 그대로 베끼면 안 되고 전이를 다시 짰다:</p><ul><li>상신 = <code>IN_PROGRESS</code> + step1 <code>WAITING</code>, <code>CURRENT_STEP=1</code>, <code>DUE_AT = 상신시각 + dueHours</code></li><li>처리는 <strong>현재 단계의 WAITING + 그 단계 결재자 본인만</strong> (아니면 403)</li><li>1단계 승인 → <code>CURRENT_STEP++</code>(여전히 IN_PROGRESS), 마지막 승인 → <code>APPROVED</code>, 중간 반려 → <code>REJECTED</code> 즉시 종료</li></ul><p><code>lines</code>/<code>steps</code> 는 MyBatis <strong>nested-select</strong> 로 채워 record 를 불변으로 유지했고 (<code>UserMapper</code> 의 roles 패턴 답습), 지연(overdue) 임계시각은 H2/Oracle 날짜연산 비호환을 피하려고 <strong>서비스에서 계산해 파라미터로</strong> 넘겼다.</p><h2 id="us6-—-레거시의-버그를-그대로-옮기지-않기" tabindex="-1">US6 — 레거시의 버그를 그대로 옮기지 않기 <a class="header-anchor" href="#us6-—-레거시의-버그를-그대로-옮기지-않기" aria-label="Permalink to &quot;US6 — 레거시의 버그를 그대로 옮기지 않기&quot;">​</a></h2><p>권한 신청은 US2(권한 반영)와 US5(결재)를 잇는 고리다. 이전 소스에 명백한 버그가 있었다:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">case</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;MENU&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    permissionMapper.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">insertRoleMenu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(request.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getTargetId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), request.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getTargetId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// roleId, menuId 둘 다 targetId</span></span></code></pre></div><p>이걸 그대로 옮기면 안 된다. 타겟에선 <strong>신청자의 각 역할에 <code>SYS_ROLE_MENU</code> 를 멱등 upsert</strong> 하도록 교정했다(ROLE 신청은 <code>SYS_USER_ROLE</code>). 결정 단일점은 계약대로 관리자 <code>/{id}/action</code>, US5 연동은 선택(<code>approvalTemplateId</code>+<code>approverIds</code> 주면 결재 상신· <code>APPROVAL_ID</code> 연결, 결정 시 연결 결재도 <code>force</code> 동기화). 테스트는 &quot;MENU 신청+결재연동 → 승인 → <code>/menus/my</code> 에 메뉴 노출 + 연결 결재 APPROVED&quot;까지 한 흐름으로 확인한다.</p><h2 id="us7-—-없는-건-만들고-범위-밖은-경계를-긋는다" tabindex="-1">US7 — 없는 건 만들고, 범위 밖은 경계를 긋는다 <a class="header-anchor" href="#us7-—-없는-건-만들고-범위-밖은-경계를-긋는다" aria-label="Permalink to &quot;US7 — 없는 건 만들고, 범위 밖은 경계를 긋는다&quot;">​</a></h2><p>이전 소스엔 <strong>메일만 있고 파일 모듈이 없었다</strong>. 파일은 계약·data-model 기준으로 새로 썼다(파일시스템 저장 + <code>SYS_FILE</code> 메타 + <code>AUDIT_FILE_LOG</code>). 그 과정에서 US4 가 만든 <code>AUDIT_FILE_LOG</code> <strong>조회 경로는 있는데 기록 경로가 없다</strong>는 걸 발견해 <code>AuditService#recordFile</code> 를 추가했다 — US4 의 <code>/audit/file-logs</code> 가 비로소 데이터를 갖게 됐다.</p><p>메일은 <strong>실 SMTP 를 범위 밖</strong>으로 명시(plan 의 &quot;SYS_SETTING 분리, research 잔여&quot;)하고, <code>MailService#dispatch</code> 를 no-op 으로 두되 발송 시도·결과(SENT/FAILED)·재시도 횟수는 <code>SYS_MAIL_LOG</code> 에 기록한다. 연동할 땐 <code>dispatch</code> 한 메서드만 갈아끼우면 된다.</p><h2 id="phase-10-—-데모가-헌법의-참조-출처를-처음-썼다" tabindex="-1">Phase 10 — 데모가 헌법의 참조 출처를 처음 썼다 <a class="header-anchor" href="#phase-10-—-데모가-헌법의-참조-출처를-처음-썼다" aria-label="Permalink to &quot;Phase 10 — 데모가 헌법의 참조 출처를 처음 썼다&quot;">​</a></h2><p>마감의 백미는 <strong>VuGrid 데모</strong>다. 003 에서 반입한 <code>vendor/vugrid/</code>(= <code>C:/ax/vugrid</code> 산출물)를 <code>/vugrid/**</code> 로 정적 서빙하는 구조를 재사용해, <code>grid-demo.html</code> 이 시드 관리자로 <strong>자동 로그인 → <code>/api/v1/users</code> + <code>/api/v1/audit/login-history</code> 2종을 실 API 로 조회</strong> 해 두 개의 그리드로 렌더하도록 확장했다. 정적 페이지가 토큰을 받아 같은 출처의 보호 API 를 부르는, 가장 단순한 데모 형태다.</p><p>격리(SC-7)·성능(SC-4)은 테스트로 못박았다. <code>PlatformIsolationTest</code> 는 플랫폼 서비스 13종 적재 + defect/batch/레거시(<code>com.clear</code>) 빈 0 을 단언하고, <code>AuditPerformanceTest</code> 는 3,000건 로그인 이력에서 기간 검색이 3초 내인지 확인한다(<code>IX_LOGIN_HISTORY_AT</code>).</p><h2 id="마무리" tabindex="-1">마무리 <a class="header-anchor" href="#마무리" aria-label="Permalink to &quot;마무리&quot;">​</a></h2><p>US1~US7 + Phase 10 으로 <strong>22개 기능 백엔드가 전부 동작</strong>한다(SC-1). spec/plan/tasks 의 <code>status</code> 를 <code>done</code> 으로 올리고, spec 의 옛 경로(<code>d:\\ax\\lego</code>)도 헌법과 맞춰 <code>C:/ax/lego</code> 로 보정했다. 남은 건 운영 Oracle 기동 시의 수동 데모 확인과, 보류해 둔 springdoc·실 SMTP· datasource-proxy→AUDIT_SQL_LOG 연동 같은 후속뿐이다.</p>`,19)])])}const g=o(t,[["render",c]]);export{u as __pageData,g as default};
